  "private": true,
  "version": "0.0.0",
  "type": "module",
  "scripts": {
    "dev": "vite",
    "build": "vite build",
    "preview": "vite preview"
  },
  "dependencies": {
    "react": "^18.3.1",
    "react-dom": "^18.3.1"
  },
  "devDependencies": {
    "@vitejs/plugin-react": "^4.3.1",
    "vite": "^5.4.8"
  }
}

export default function App() {
  return (
    <div className="page">
      <h1>React + Vite Project</h1>
      <p>This starter project was generated by the builder. nice</p>
    </div>
  );
}

:root {
  font-family: Inter, system-ui, Arial, sans-serif;
}

body {
  margin: 0;
  background: #f5f7fb;
  color: #0f172a;
}

.page {
  max-width: 900px;
  margin: 80px auto;
  background: white;
  padding: 32px;
  border-radius: 16px;
  box-shadow: 0 12px 30px rgba(15, 23, 42, 0.08);
}

import React from "react";
import ReactDOM from "react-dom/client";
import App from "./App";
import "./index.css";

ReactDOM.createRoot(document.getElementById("root")).render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import { defineConfig } from "vite";
import react from "@vitejs/plugin-react";

export default defineConfig({
  plugins: [react()],
});

body {
  font-family: Arial, sans-serif;
  margin: 0;
  background: #f4f7fd;
}

.page {
  max-width: 800px;
  margin: 60px auto;
  background: white;
  pading: 30px;
  border-radius: 12px;
  box-shadow: 0 8px 24px rgba(0,0,0,0.08);
}

const aboutActionBtn = document.getElementById("aboutActionBtn");
const aboutForm = document.getElementById("aboutForm");
const updatedText = document.getElementById("updatedText");

function updateAboutTime() {
  const now = new Date();
  if (updatedText) {
    updatedText.textContent = now.toLocaleString();
  }
}

updateAboutTime();

if (aboutActionBtn) {
  aboutActionBtn.addEventListener("click", () => {
    alert("Welcome to the About page demo.");
  });
}

if (aboutForm) {
  aboutForm.addEventListener("submit", (event) => {
    event.preventDefault();
    const questionEl = document.getElementById("question");
    const value = questionEl ? questionEl.value.trim() : "";

    if (!value) {
      alert("Please enter a question first.");
      return;
    }

    alert(`Your question was captured: ${value}`);
  });
}

:root {
  --bg: #f8fafc;
  --surface: #ffffff;
  --border: #dbeafe;
  --text: #0f172a;
  --muted: #475569;
  --primary: #7c3aed;
  --primary-dark: #6d28d9;
  --soft: #ede9fe;
  --shadow: 0 12px 28px rgba(15, 23, 42, 0.08);
  --radius: 18px;
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  background: linear-gradient(180deg, #f8fafc 0%, #f5f3ff 100%);
  color: var(--text);
  font-family: system-ui, Arial, sans-serif;
}

a {
  color: inherit;
  text-decoration: none;
}

.about-page {
  min-height: 100vh;
}

.page-header,
.container {
  max-width: 1100px;
  margin: 0 auto;
  padding: 20px 18px;
}

.page-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 16px;
  flex-wrap: wrap;
}

.brand {
  font-weight: 800;
  font-size: 1.1rem;
}

.nav {
  display: flex;
  gap: 16px;
  flex-wrap: wrap;
}

.nav a {
  color: var(--muted);
  font-weight: 600;
}

.nav a:hover {
  color: var(--primary);
}

.hero {
  display: grid;
  grid-template-columns: 1.4fr 1fr;
  gap: 20px;
  align-items: center;
  padding-top: 18px;
}

.badge,
.section-tag {
  display: inline-block;
  padding: 6px 12px;
  border-radius: 999px;
  background: var(--soft);
  color: var(--primary-dark);
  font-weight: 700;
  font-size: 0.85rem;
}

.hero h1 {
  margin: 14px 0 14px;
  font-size: clamp(2rem, 4vw, 3.2rem);
  line-height: 1.15;
}

.hero p {
  color: var(--muted);
  line-height: 1.7;
}

.hero-actions {
  display: flex;
  gap: 12px;
  flex-wrap: wrap;
  margin-top: 20px;
}

.primary-btn,
.secondary-btn {
  border: none;
  border-radius: 12px;
  padding: 12px 18px;
  font-weight: 700;
  cursor: pointer;
  font-size: 0.95rem;
}

.primary-btn {
  background: var(--primary);
  color: white;
}

.primary-btn:hover {
  background: var(--primary-dark);
}

.secondary-btn {
  background: white;
  color: var(--text);
  border: 1px solid #ddd6fe;
}

.info-card,
.skill-card,
.team-card,
.contact-box {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  box-shadow: var(--shadow);
}

.info-card {
  padding: 22px;
}

.section {
  padding-top: 24px;
  padding-bottom: 8px;
}

.section-head {
  margin-bottom: 18px;
}

.section-head h2 {
  margin: 12px 0 0;
  font-size: 2rem;
}

.skill-grid,
.team-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 18px;
}

.skill-card,
.team-card {
  padding: 20px;
}

.skill-card h3,
.team-card h3 {
  margin-top: 0;
}

.skill-card p,
.team-card p {
  margin-bottom: 0;
  color: var(--muted);
  line-height: 1.7;
}

.contact-box {
  padding: 22px;
}

.contact-box label {
  display: block;
  margin-bottom: 8px;
  font-weight: 600;
}

.contact-box textarea {
  width: 100%;
  border: 1px solid #c4b5fd;
  border-radius: 12px;
  padding: 12px 14px;
  font: inherit;
  margin-bottom: 14px;
  outline: none;
}

.contact-box textarea:focus {
  border-color: var(--primary);
}

.footer-note {
  text-align: center;
  color: var(--muted);
  margin-top: 18px;
}

@media (max-width: 900px) {
  .hero,
  .skill-grid,
  .team-grid {
    grid-template-columns: 1fr;
  }
}

const demoBtn = document.getElementById("demoBtn");
const timeText = document.getElementById("timeText");
const yearText = document.getElementById("yearText");
const contactForm = document.getElementById("contactForm");

function updateTime() {
  const now = new Date();
  if (timeText) {
    timeText.textContent = now.toLocaleString();
  }

  if (yearText) {
    yearText.textContent = String(now.getFullYear());
  }
}

updateTime();
setInterval(updateTime, 1000);

if (demoBtn) {
  demoBtn.addEventListener("click", () => {
    alert("Your builder can load HTML, CSS, and JavaScript together.");
  });
}

if (contactForm) {
  contactForm.addEventListener("submit", (event) => {
    event.preventDefault();
    alert("Demo form submitted successfully.");
  });
}

