{
  "name": "cmnexa-react-project",
  "private": true,
  "version": "1.0.0",
  "type": "module",
  "scripts": {
    "dev": "vite",
    "build": "vite build",
    "preview": "vite preview"
  },
  "dependencies": {
    "@vitejs/plugin-react": "^5.2.0",
    "vite": "^6.4.1",
    "react": "^19.2.5",
    "react-dom": "^19.2.5",
    "framer-motion": "^12.38.0",
    "lucide-react": "^1.11.0",
    "axios": "^1.15.2"
  },
  "devDependencies": {}
}

import { motion } from "framer-motion";
import { ArrowRight, Sparkles } from "lucide-react";

export default function Hero() {
  return (
    <section className="hero-section">
      <div className="hero-bg hero-bg-one"></div>
      <div className="hero-bg hero-bg-two"></div>

      <motion.div
        className="hero-content"
        initial={{ opacity: 0, y: 28 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.7, ease: "easeOut" }}
      >
        <div className="hero-badge">
          <Sparkles size={16} />
          <span>Professional React + Vite Project</span>
        </div>

        <h1>
          Build modern digital products with clean code and beautiful UI.
        </h1>

        <p>
          A premium React landing page created inside Dynamic Page Builder using
          component-based architecture, Framer Motion animations, and Lucide
          icons.
        </p>

        <div className="hero-actions">
          <a href="#projects" className="primary-btn">
            View Projects
            <ArrowRight size={18} />
          </a>

          <a href="#contact" className="secondary-btn">
            Start a Project
          </a>
        </div>
      </motion.div>

      <motion.div
        className="hero-card"
        initial={{ opacity: 0, scale: 0.92, rotate: -2 }}
        animate={{ opacity: 1, scale: 1, rotate: 0 }}
        transition={{ delay: 0.25, duration: 0.7, ease: "easeOut" }}
      >
        <div className="code-window-header">
          <span></span>
          <span></span>
          <span></span>
        </div>

        <pre>
{`function Project() {
  return (
    <Experience
      design="premium"
      preview="live"
      framework="React"
    />
  );
}`}
        </pre>
      </motion.div>
    </section>
  );
}

import { motion } from "framer-motion";
import { Globe2, LayoutDashboard, Rocket } from "lucide-react";

const services = [
  {
    icon: Globe2,
    title: "Web Applications",
    description:
      "Responsive, fast, and scalable web applications built with modern frontend tools.",
  },
  {
    icon: LayoutDashboard,
    title: "Dashboards",
    description:
      "Clean admin dashboards and business systems with professional UI/UX patterns.",
  },
  {
    icon: Rocket,
    title: "Startup MVPs",
    description:
      "From idea to launch-ready product using React, APIs, and modern deployment workflows.",
  },
];

export default function Services() {
  return (
    <section id="services" className="section">
      <div className="section-head">
        <span className="section-kicker">Services</span>
        <h2>What this React project demonstrates</h2>
      </div>

      <div className="service-grid">
        {services.map((service, index) => {
          const Icon = service.icon;

          return (
            <motion.article
              className="service-card"
              key={service.title}
              initial={{ opacity: 0, y: 24 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ delay: index * 0.1, duration: 0.55 }}
            >
              <div className="service-icon">
                <Icon size={24} />
              </div>

              <h3>{service.title}</h3>
              <p>{service.description}</p>
            </motion.article>
          );
        })}
      </div>
    </section>
  );
}

import Navbar from "./components/Navbar.jsx";
import Hero from "./components/Hero.jsx";
import Services from "./components/Services.jsx";
import Projects from "./components/Projects.jsx";
import Contact from "./components/Contact.jsx";

export default function App() {
  return (
    <div className="app">
      <Navbar />
      <main>
        <Hero />
        <Services />
        <Projects />
        <Contact />
      </main>
    </div>
  );
}

import { motion } from "framer-motion";
import { projects } from "../data/projects.js";

export default function Projects() {
  return (
    <section id="projects" className="section projects-section">
      <div className="section-head">
        <span className="section-kicker">Projects</span>
        <h2>Real project-style component composition</h2>
      </div>

      <div className="project-grid">
        {projects.map((project, index) => (
          <motion.article
            className="project-card"
            key={project.title}
            initial={{ opacity: 0, y: 24 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            transition={{ delay: index * 0.1, duration: 0.55 }}
          >
            <span className="project-category">{project.category}</span>
            <h3>{project.title}</h3>
            <p>{project.description}</p>

            <div className="stack-list">
              {project.stack.map((item) => (
                <span key={item}>{item}</span>
              ))}
            </div>
          </motion.article>
        ))}
      </div>
    </section>
  );
}

export const projects = [
  {
    title: "MediForecast",
    category: "AI Healthcare Platform",
    description:
      "AI-powered drug demand forecasting and digital prescription management system for pharmacy operations.",
    stack: ["React", "Python", "PostgreSQL", "AI"],
  },
  {
    title: "Cake Shop Web App",
    category: "Full-stack E-commerce",
