    stack: ["React", "Node.js", "MongoDB", "JavaScript"],
  },
  {
    title: "Dynamic Page Builder",
    category: "Multi-framework Builder",
    description:
      "Browser-based page builder with Monaco Editor, React/Vue/HTML project support, and live preview workflow.",
    stack: ["Astro", "Vite", "React", "Vue"],
