];

:root {
  --bg: #070a12;
  --surface: #0f172a;
  --surface-soft: #111827;
  --card: rgba(255, 255, 255, 0.08);
  --border: rgba(255, 255, 255, 0.12);
  --text: #f8fafc;
  --muted: #94a3b8;
  --primary: #38bdf8;
  --primary-dark: #0284c7;
  --accent: #a78bfa;
  --success: #34d399;
  --shadow: 0 28px 90px rgba(0, 0, 0, 0.35);
  font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont,
    "Segoe UI", sans-serif;
}

* {
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
}

body {
  margin: 0;
  background:
    radial-gradient(circle at top left, rgba(56, 189, 248, 0.18), transparent 32%),
    radial-gradient(circle at top right, rgba(167, 139, 250, 0.14), transparent 28%),
    var(--bg);
  color: var(--text);
}

a {
  color: inherit;
  text-decoration: none;
}

button,
input,
textarea {
  font: inherit;
}

.app {
  min-height: 100vh;
  overflow-x: hidden;
}

.navbar {
  position: sticky;
  top: 0;
  z-index: 20;
  height: 72px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 24px;
  padding: 0 7vw;
  border-bottom: 1px solid var(--border);
  background: rgba(7, 10, 18, 0.72);
  backdrop-filter: blur(18px);
}

.brand {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  font-weight: 900;
  letter-spacing: -0.03em;
}

.brand-icon {
  width: 38px;
  height: 38px;
  display: grid;
  place-items: center;
  border-radius: 12px;
  background: linear-gradient(135deg, var(--primary), var(--accent));
  color: white;
  box-shadow: 0 14px 40px rgba(56, 189, 248, 0.26);
}

.nav-links {
  display: flex;
  align-items: center;
  gap: 26px;
  color: var(--muted);
  font-weight: 700;
  font-size: 14px;
}

.nav-links a:hover {
  color: var(--text);
}

.nav-button {
  display: none;
  align-items: center;
  gap: 8px;
  border: 1px solid var(--border);
  border-radius: 999px;
  background: var(--card);
  color: var(--text);
  padding: 10px 14px;
}

.hero-section {
  position: relative;
  min-height: calc(100vh - 72px);
  display: grid;
  grid-template-columns: minmax(0, 1.05fr) minmax(320px, 0.95fr);
  align-items: center;
  gap: 60px;
  padding: 90px 7vw;
}

.hero-bg {
  position: absolute;
  border-radius: 999px;
  filter: blur(28px);
  opacity: 0.5;
  pointer-events: none;
}

.hero-bg-one {
  width: 240px;
  height: 240px;
  left: 5%;
  top: 12%;
  background: rgba(56, 189, 248, 0.25);
}

.hero-bg-two {
  width: 280px;
  height: 280px;
  right: 12%;
  bottom: 10%;
  background: rgba(167, 139, 250, 0.22);
}

.hero-content,
.hero-card {
  position: relative;
  z-index: 1;
}

.hero-badge,
.section-kicker {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 18px;
  padding: 8px 12px;
  border: 1px solid rgba(56, 189, 248, 0.3);
  border-radius: 999px;
  background: rgba(56, 189, 248, 0.1);
  color: #7dd3fc;
  font-size: 13px;
  font-weight: 900;
  letter-spacing: 0.05em;
  text-transform: uppercase;
}

.hero-content h1 {
  max-width: 780px;
  margin: 0;
  font-size: clamp(42px, 6vw, 82px);
  line-height: 0.94;
  letter-spacing: -0.075em;
}

.hero-content p {
  max-width: 650px;
  margin: 26px 0 0;
  color: var(--muted);
  font-size: 18px;
  line-height: 1.75;
}

.hero-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 14px;
  margin-top: 34px;
}

.primary-btn,
.secondary-btn {
  min-height: 50px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  border-radius: 16px;
  padding: 0 18px;
  font-weight: 900;
}

.primary-btn {
  background: linear-gradient(135deg, var(--primary), var(--accent));
  color: white;
  box-shadow: 0 18px 50px rgba(56, 189, 248, 0.25);
}

.secondary-btn {
  border: 1px solid var(--border);
  background: var(--card);
  color: var(--text);
}

