const yearElements = document.querySelectorAll("[data-year]");
const navLinks = document.querySelectorAll(".nav-link");
const demoButtons = document.querySelectorAll("[data-demo-button]");
const contactForms = document.querySelectorAll("[data-contact-form]");
const statNumbers = document.querySelectorAll("[data-count]");

yearElements.forEach((el) => {
  el.textContent = String(new Date().getFullYear());
});

navLinks.forEach((link) => {
  try {
    const linkPath = new URL(link.href, window.location.origin).pathname;
    if (linkPath === window.location.pathname) {
      link.classList.add("is-active");
    }
  } catch {
    // ignore malformed URLs
  }
});

demoButtons.forEach((button) => {
  button.addEventListener("click", () => {
    alert("This demo was generated from your Dynamic Page Builder project.");
  });
});

contactForms.forEach((form) => {
  form.addEventListener("submit", (event) => {
    event.preventDefault();

    const nameInput = form.querySelector('input[name="name"]');
    const emailInput = form.querySelector('input[name="email"]');
    const messageInput = form.querySelector('textarea[name="message"]');

    const name = nameInput ? nameInput.value.trim() : "";
    const email = emailInput ? emailInput.value.trim() : "";
    const message = messageInput ? messageInput.value.trim() : "";

    if (!name || !email || !message) {
      alert("Please fill in all fields before submitting.");
      return;
    }

    alert(`Thanks ${name}! Your demo message was captured successfully.`);
    form.reset();
  });
});

statNumbers.forEach((item) => {
  const finalValue = Number(item.getAttribute("data-count") || "0");
  if (!Number.isFinite(finalValue) || finalValue <= 0) return;

  let current = 0;
  const step = Math.max(1, Math.ceil(finalValue / 40));

  const timer = setInterval(() => {
    current += step;
    if (current >= finalValue) {
      current = finalValue;
      clearInterval(timer);
    }
    item.textContent = String(current);
  }, 30);
});

