    linear-gradient(180deg, #f8fafc 0%, #eef2ff 100%);
  color: var(--text);
}

a {
  color: inherit;
  text-decoration: none;
}

img {
  max-width: 100%;
  display: block;
}

.container {
  width: min(100%, var(--max));
  margin: 0 auto;
  padding: 0 18px;
}

.site-header {
  position: sticky;
  top: 0;
  z-index: 10;
  backdrop-filter: blur(10px);
  background: rgba(248, 250, 252, 0.82);
  border-bottom: 1px solid rgba(226, 232, 240, 0.8);
}

.nav-wrap {
  min-height: 74px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
}

.brand {
  display: flex;
  align-items: center;
  gap: 12px;
}

.brand-mark {
  width: 42px;
  height: 42px;
  border-radius: 14px;
  background: linear-gradient(135deg, var(--primary) 0%, var(--accent) 100%);
  display: grid;
  place-items: center;
  color: white;
  font-weight: 800;
  box-shadow: var(--shadow);
}

.brand-text strong {
  display: block;
  font-size: 1rem;
}

.brand-text span {
  display: block;
  color: var(--muted);
  font-size: 0.82rem;
}

.nav {
  display: flex;
  gap: 10px;
  flex-wrap: wrap;
}

.nav-link {
  padding: 10px 14px;
  border-radius: 999px;
  color: var(--muted);
  font-weight: 600;
  transition: 0.2s ease;
}

.nav-link:hover,
.nav-link.is-active {
  background: #dbeafe;
  color: var(--primary-dark);
}

.hero {
  padding: 72px 0 40px;
}

.hero-grid {
  display: grid;
  grid-template-columns: 1.2fr 0.8fr;
  gap: 28px;
  align-items: center;
}

.badge {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 8px 14px;
  border-radius: 999px;
  background: #dbeafe;
  color: var(--primary-dark);
  font-weight: 700;
  font-size: 0.88rem;
}

.hero h1 {
  margin: 18px 0 16px;
  font-size: clamp(2.3rem, 5vw, 4.3rem);
  line-height: 1.08;
}

.hero p {
  margin: 0;
  max-width: 720px;
  color: var(--muted);
  font-size: 1.02rem;
  line-height: 1.8;
}

.hero-actions {
  display: flex;
  gap: 12px;
  flex-wrap: wrap;
  margin-top: 26px;
}

.btn,
.btn-outline {
  border: none;
  border-radius: 14px;
  padding: 13px 18px;
  font-weight: 700;
  cursor: pointer;
  font-size: 0.95rem;
}

.btn {
  background: linear-gradient(135deg, var(--primary) 0%, var(--accent) 100%);
  color: white;
  box-shadow: var(--shadow);
}

.btn:hover {
  filter: brightness(1.05);
}

.btn-outline {
  background: white;
  color: var(--text);
  border: 1px solid var(--border);
}

.hero-card,
.kpi-card,
.feature-card,
.service-card,
.story-card,
.info-card,
.contact-card,
.contact-form,
.team-card,
.process-card {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  box-shadow: var(--shadow);
}

.hero-card {
  padding: 24px;
}

.hero-card h3 {
  margin-top: 0;
  margin-bottom: 12px;
}

.hero-list {
  margin: 0;
  padding-left: 18px;
  color: var(--muted);
  line-height: 1.9;
}

.section {
  padding: 34px 0;
}

.section-head {
  margin-bottom: 20px;
}

.section-head h2 {
  margin: 12px 0 0;
  font-size: clamp(1.8rem, 3vw, 2.6rem);
}

.section-head p {
  margin: 12px 0 0;
  color: var(--muted);
  max-width: 760px;
  line-height: 1.8;
}

.kpi-grid,
.feature-grid,
.service-grid,
.team-grid,
.process-grid {
  display: grid;
  gap: 18px;
}

.kpi-grid {
  grid-template-columns: repeat(4, 1fr);
}

.feature-grid {
  grid-template-columns: repeat(3, 1fr);
}

.service-grid,
.process-grid,
.team-grid {
  grid-template-columns: repeat(3, 1fr);
}

.kpi-card,
.feature-card,
.service-card,
.team-card,
.process-card {
  padding: 22px;
}

.kpi-number {
  font-size: 2rem;
  font-weight: 800;
  color: var(--primary-dark);
}

.kpi-label {
  margin-top: 8px;
  color: var(--muted);
  font-weight: 600;
}

.feature-card h3,
.service-card h3,
.team-card h3,
.process-card h3 {
  margin-top: 0;
  margin-bottom: 10px;
}

.feature-card p,
.service-card p,
.team-card p,
.process-card p {
  margin: 0;
  color: var(--muted);
  line-height: 1.8;
}

.split-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 18px;
}

.story-card,
.info-card,
.contact-card {
  padding: 22px;
}

.info-list {
  margin: 0;
  padding-left: 18px;
  color: var(--muted);
  line-height: 1.9;
}

.quote {
  margin: 0;
  color: var(--muted);
  line-height: 1.8;
  font-style: italic;
}

.contact-layout {
  display: grid;
  grid-template-columns: 0.9fr 1.1fr;
  gap: 18px;
}

.contact-form {
  padding: 22px;
}

.field-row {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 14px;
}

.field {
  margin-bottom: 14px;
}

.field label {
  display: block;
  margin-bottom: 6px;
  font-weight: 600;
}

.field input,
.field textarea {
  width: 100%;
  border: 1px solid #cbd5e1;
  border-radius: 14px;
  padding: 12px 14px;
  font: inherit;
  outline: none;
  background: white;
}

.field input:focus,
.field textarea:focus {
  border-color: var(--primary);
}

.footer {
  padding: 26px 0 34px;
  color: var(--muted);
}

.footer-line {
  border-top: 1px solid var(--border);
  padding-top: 18px;
  display: flex;
  justify-content: space-between;
  gap: 14px;
  flex-wrap: wrap;
}

.small-tag {
  display: inline-block;
  padding: 6px 10px;
  border-radius: 999px;
  background: #ede9fe;
  color: #6d28d9;
  font-size: 0.8rem;
  font-weight: 700;
}

.highlight {
  color: var(--primary-dark);
}

@media (max-width: 980px) {
  .hero-grid,
  .split-grid,
  .contact-layout,
  .kpi-grid,
  .feature-grid,
  .service-grid,
  .team-grid,
  .process-grid,
  .field-row {
    grid-template-columns: 1fr;
  }
}

